const long long MOD = 998244353LL;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;
    long long ans = 0;
    long long start = 1;
    while (start <= n) {
        long long end = min(n, start * 10 - 1);
        long long cnt = end - start + 1;
        long long add = (cnt % MOD) * ((cnt + 1) % MOD) % MOD;
        add = add * ((MOD + 1) / 2) % MOD;
        ans = (ans + add) % MOD;
        start *= 10;
    }
    cout << ans << '\n';
    return 0;
}

