const long long MOD = 998244353LL;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<long long> dp(10, 0);
    for (int d = 1; d <= 9; ++d) dp[d] = 1;
    for (int len = 2; len <= n; ++len) {
        vector<long long> ndp(10, 0);
        for (int d = 1; d <= 9; ++d) {
            for (int e = max(1, d - 1); e <= min(9, d + 1); ++e) {
                ndp[e] = (ndp[e] + dp[d]) % MOD;
            }
        }
        dp.swap(ndp);
    }
    long long ans = 0;
    for (int d = 1; d <= 9; ++d) ans = (ans + dp[d]) % MOD;
    cout << ans << '\n';
    return 0;
}

